import json
import os
import time
from pathlib import Path

import cocotb
from cocotb.clock import Clock
from cocotb.triggers import ClockCycles, RisingEdge


ADDR_CTRL = 0x0
ADDR_COUNT = 0x4
ADDR_COMPARE = 0x8
ADDR_STATUS = 0xC

_bins = {
    "reset_defaults": False,
    "apb_write_ctrl": False,
    "apb_write_compare": False,
    "apb_readback": False,
    "counter_increments": False,
    "counter_halts": False,
    "compare_irq": False,
    "status_w1c_clear": False,
    "irq_mask": False,
}


def _set_bin(name):
    _bins[name] = True


async def _reset(dut):
    dut.psel.value = 0
    dut.penable.value = 0
    dut.pwrite.value = 0
    dut.paddr.value = 0
    dut.pwdata.value = 0
    dut.pstrb.value = 0
    dut.rst_n.value = 0
    await ClockCycles(dut.clk, 4)
    dut.rst_n.value = 1
    await ClockCycles(dut.clk, 2)


async def _apb_write(dut, addr, data):
    dut.paddr.value = addr
    dut.pwrite.value = 1
    dut.pwdata.value = data
    dut.pstrb.value = 0xF
    dut.psel.value = 1
    dut.penable.value = 0
    await RisingEdge(dut.clk)
    dut.penable.value = 1
    await RisingEdge(dut.clk)
    assert int(dut.pready.value) == 1
    assert int(dut.pslverr.value) == 0
    dut.psel.value = 0
    dut.penable.value = 0
    dut.pwrite.value = 0
    dut.paddr.value = 0
    dut.pwdata.value = 0
    dut.pstrb.value = 0
    await RisingEdge(dut.clk)


async def _apb_read(dut, addr):
    dut.paddr.value = addr
    dut.pwrite.value = 0
    dut.psel.value = 1
    dut.penable.value = 0
    await RisingEdge(dut.clk)
    dut.penable.value = 1
    await RisingEdge(dut.clk)
    assert int(dut.pready.value) == 1
    assert int(dut.pslverr.value) == 0
    value = int(dut.prdata.value)
    dut.psel.value = 0
    dut.penable.value = 0
    dut.paddr.value = 0
    await RisingEdge(dut.clk)
